    let _temp_dir = setup_test_environment();

    // Test that we can query by file extension
    let template = "MNI152NLin2009cAsym";

    // Common extensions in neuroimaging
    let extensions = vec![".nii.gz", ".nii", ".json"];

    for ext in extensions {
        let mut query = HashMap::new();
        query.insert("ext".to_string(), ext.to_string());

        match ls(template, Some(&query)) {
            Ok(files) => {
                println!("Found {} files with extension {}", files.len(), ext);

                // Verify all files have the correct extension
                for file in &files {
                    assert!(file.to_string_lossy().ends_with(ext),
                            "File {:?} should end with {}", file, ext);
                }
            }
            Err(_) => {
                println!("No files found with extension {}", ext);
            }
        }
    }
}

#[tokio::test]
#[ignore] // Requires network access
async fn test_concurrent_template_access() {
    let _temp_dir = setup_test_environment();

    // Test concurrent access to multiple templates
    let test_templates = vec![
        "MNI152NLin2009cAsym",
        "MNI152Lin",
        "fsaverage",
        "fsLR",
    ];

    let mut tasks = Vec::new();

    for template in test_templates {
        let template = template.to_string();
        let task = tokio::spawn(async move {
            // Try to list files for each template
            match ls(&template, None) {
                Ok(files) => {
                    println!("Template {} has {} files", template, files.len());
                    (template, files.len())
                }
                Err(e) => {
                    println!("Failed to list files for {}: {}", template, e);
                    (template, 0)
                }
            }
        });
        tasks.push(task);
    }

    // Wait for all tasks to complete
    let results = futures::future::join_all(tasks).await;

    // Verify we got results for all templates
    for result in results {
        let (template, file_count) = result.expect("Task should not panic");
        println!("Template {} completed with {} files", template, file_count);
    }
}

#[tokio::test]
#[ignore] // Requires network access and downloads files
async fn test_parallel_download_performance() {
    let _temp_dir = setup_test_environment();

    // Find files to download for performance testing
    let mut query = HashMap::new();
    query.insert("suffix".to_string(), "mask".to_string());

    match ls("MNI152NLin2009cAsym", Some(&query)) {
        Ok(files) => {
            if files.len() >= 3 {
                println!("Testing parallel download with {} files", files.len());

                // Measure sequential download time
                let start_seq = std::time::Instant::now();
                let _seq_results = get("MNI152NLin2009cAsym", Some(&query))
                    .expect("Sequential download failed");
                let seq_duration = start_seq.elapsed();

                // Clear cache for fair comparison
                let cache_dir = std::env::var("TEMPLATEFLOW_HOME").unwrap();
                std::fs::remove_dir_all(&cache_dir).ok();
                std::fs::create_dir_all(&cache_dir).ok();

                // Measure parallel download time
                let start_par = std::time::Instant::now();
                let _par_results = get_multiple_async("MNI152NLin2009cAsym", Some(&query)).await
                    .expect("Parallel download failed");
                let par_duration = start_par.elapsed();

                println!("Sequential download: {:?}", seq_duration);
                println!("Parallel download: {:?}", par_duration);

                // Parallel should be faster for multiple files
                // (or at least not significantly slower)
                assert!(par_duration.as_secs_f64() <= seq_duration.as_secs_f64() * 1.5,
                        "Parallel download should not be much slower than sequential");
            } else {
                println!("Not enough files for performance test");
            }
        }
        Err(_) => {
            println!("Could not find files for performance test");
        }
    }
}

#[test]
#[ignore] // Requires network access
fn test_bids_entity_validation() {
    let _temp_dir = setup_test_environment();

    // Test that the API properly handles various BIDS entities
    let template = "MNI152NLin2009cAsym";

    // Valid BIDS entities that should work
    let valid_entities = vec![
        ("res", vec!["01", "02", "1", "2"]),
        ("suffix", vec!["T1w", "T2w", "mask", "dseg", "probseg"]),
